1	/**
2	 * Rule Proposer — 固定機能.
3	 *
4	 * 5 分おきに「新しいチャット発言フック rule を提案するか」を AI に問う.
5	 * 既存の rule engine (default-tick) とは独立. tick で chat post する役割と
6	 * 「rule そのものを増やす」役割を分離して、 後者専用の loop を持つ.
7	 *
8	 * 出力 action: add_rule | skip のみ受け付ける. (post / remove は engine 側).
9	 */
10	
11	import type { RulesRepo } from "../db/rules-repo.js";
12	import type { SessionsRepo } from "../db/sessions-repo.js";
13	import type { ChatRepo } from "../db/chat-repo.js";
14	import { runClaude } from "./claude-runner.js";
15	import { handleAction } from "./handler.js";
16	import { createChildLogger } from "../shared/logger.js";
17	
18	const log = createChildLogger("rule-proposer");
19	
20	const DEFAULT_TICK_MS = 5 * 60 * 1000;       // 5 分 (admin で上書き可)
21	const STARTUP_DELAY_MS = 30 * 1000;  // 起動 30 秒後に初回
22	
23	export interface ProposerDeps {
24	  rules: RulesRepo;
25	  sessions: SessionsRepo;
26	  chat: ChatRepo;
27	  /** test 用. true で claude CLI を呼ばずスキップ. */
28	  disable_claude?: boolean;
29	  /** enabled な ai 由来 rule 数がこれ以上なら新規提案を skip (rule 雪だるま防止). */
30	  maxAiRules?: number;
31	  /**
32	   * Runtime kill-switch (AdminState.getRulesEnabled() の否定を期待).
33	   * true で runOnce が claude を呼ばず skip する.
34	   */
35	  rulesDisabled?: () => boolean;
36	  /**
37	   * Tick interval in seconds. Default 300 (5 minutes). Read on each tick
38	   * via this getter so the Web UI can change cadence without restart.
39	   */
40	  intervalSec?: () => number;
41	}
42	
43	export interface ProposerHandle {
44	  stop: () => void;
45	  runOnce: () => Promise<void>;
46	}
47	
48	export function startRuleProposer(deps: ProposerDeps): ProposerHandle {
49	  let timer: NodeJS.Timeout | null = null;
50	  let firstTimer: NodeJS.Timeout | null = null;
51	  let running = false;
52	  let stopped = false;
53	
54	  async function runOnce(): Promise<void> {
55	    if (stopped || running) return;
56	    if (deps.disable_claude || process.env.CONCORDIA_DISABLE_CLAUDE === "1") {
57	      return;
58	    }
59	    if (deps.rulesDisabled?.()) {
60	      // admin が rules-enabled=false にしている. tick は走らせるが claude を呼ばない.
61	      return;
62	    }
63	
64	    running = true;
65	    try {
66	      const enabledRules = deps.rules.list({ enabled: true });
67	
68	      // cap 判定: enabled な AI 由来 rule が上限以上なら claude を呼ばず skip
69	      const cap = deps.maxAiRules;
70	      if (typeof cap === "number" && cap >= 0) {
71	        const aiRuleCount = enabledRules.filter((r) => r.added_by === "ai").length;
72	        if (aiRuleCount >= cap) {
73	          deps.rules.log({
74	            rule_id: null,
75	            action: "skip",
76	            actor: "engine",
77	            detail: `proposer cap reached: ${aiRuleCount}/${cap} ai rules enabled`,
78	          });
79	          log.info({ aiRuleCount, cap }, "rule proposer skipped (cap reached)");
80	          return;
81	        }
82	      }
83	
84	      const recentChat = deps.chat.list({ limit: 30 });
85	      const recentLogs = deps.rules.recentLogs(20);
86	      const activeSessions = deps.sessions.listSessions({ status: "active" });
87	
88	      const ctx = {
89	        now_iso: new Date().toISOString(),
90	        active_session_count: activeSessions.length,
91	        existing_rules: enabledRules.map((r) => ({
92	          id: r.id,
93	          trigger_type: r.trigger_type,
94	          tick_sec: r.tick_sec,
95	          event_kind: r.event_kind,
96	          description: r.description,
97	        })),
98	        recent_chat: recentChat.map((m) => ({
99	          channel: m.channel,
100	          author: m.author_label,
101	          ts_sec_ago: Math.floor(Date.now() / 1000) - m.ts,
102	          text: m.text.slice(0, 80),
103	        })),
104	        recent_rule_actions: recentLogs.map((l) => ({
105	          action: l.action,
106	          rule_id: l.rule_id,
107	          actor: l.actor,
108	          detail: l.detail?.slice(0, 80),
109	        })),
110	      };
111	
112	      const prompt = [
113	        "あなたは Concordia (LUDIARS multi-agent session coordinator) の **rule proposer** です.",
114	        "目的: 既存のチャット発言フック rule に足りないパターンを見つけ、 新しい rule を 1 つだけ提案するか、 提案すべきでないと判断したら skip すること.",
115	        "",
116	        "## 重要な制約",
117	        "- rule = **チャット発言フック** (いつ / どの channel に / 何を投稿するか). meta 管理ではない.",
118	        "- 既存 rule と意味的に重複する提案は禁止 (existing_rules を確認).",
119	        "- 5 分以内に同じ rule を再提案しないこと.",
120	        "- 提案する rule の id は kebab-case で 短く一意 (例: 'topic-shift-toast').",
121	        "- 何も提案する価値がないなら遠慮なく skip すること (むしろ skip がデフォルト).",
122	        "",
123	        "## 提案禁止パターン (これらを目的とする rule は提案しないこと — handler でも reject されます)",
124	        "- 無音 / 沈黙検知系 (例: 'long-silence-poke', '誰も発言していないことを知らせる'). 理由: event log で見えるので冗長.",
125	        "- 進捗 ping 系 (例: 'progress-check-ping', '進捗を聞き合う'). 理由: /v1/stat poll で完結.",
126	        "- ロール無関係な汎用雑談 (天気 / 時事 / 抽象的感想). 理由: persona の役割と紐づかない発話は noise.",
127	        "- 衝突確認 を skip して chat 開始するような rule. 理由: 衝突回避が会話より先 (作業競合の事故防止).",
128	        "",
129	        "## 出力 (JSON 1 つのみ、 余計な前置きなし)",
130	        `{"action":"add_rule","rule":{"id":"<id>","description":"<目的を 1 行>","trigger_type":"tick"|"event","tick_sec":<sec>?,"event_kind":"<kind>"?,"conditions":[],"instructions":"<AI に渡す具体的指示>","target":null,"cooldown_sec":<sec>},"reasoning":"<提案理由>"}`,
131	        `{"action":"skip","reasoning":"<提案する価値のあるパターンが見当たらない理由>"}`,
132	        "",
133	        "## 現在の状況",
134	        JSON.stringify(ctx, null, 2).slice(0, 12_000),
135	      ].join("\n");
136	
137	      const r = await runClaude(prompt);
138	      if (!r.ok) {
139	        deps.rules.log({ rule_id: null, action: "error", actor: "engine", detail: `proposer claude failed: ${r.stderr.slice(0, 200)}` });
140	        return;
141	      }
142	      const json = parseJson(r.stdout);
143	      if (!json) {
144	        deps.rules.log({ rule_id: null, action: "error", actor: "engine", detail: "proposer unparseable" });
145	        return;
146	      }
147	
148	      // proposer は add_rule / skip のみ許可
149	      const action = (json as any).action;
150	      if (action !== "add_rule" && action !== "skip") {
151	        deps.rules.log({
152	          rule_id: null,
153	          action: "error",
154	          actor: "engine",
155	          detail: `proposer returned disallowed action: ${action}`,
156	        });
157	        return;
158	      }
159	
160	      const result = handleAction({ chat: deps.chat, rules: deps.rules }, "_proposer", json);
161	      log.info({ action, applied: result.applied, detail: result.detail }, "rule proposer tick");
162	    } catch (err) {
163	      log.warn({ err: (err as Error).message }, "proposer tick failed");
164	    } finally {
165	      running = false;
