1	import { useEffect, useState } from "react";
2	import { fmtTs } from "../api.js";
3	import { useLiveQuery } from "../hooks/useWsEvent.js";
4	
5	interface RuleForm {
6	  id: string;
7	  description: string;
8	  trigger_type: "tick" | "event";
9	  tick_sec: string;
10	  event_kind: string;
11	  cooldown_sec: string;
12	  instructions: string;
13	  /** create 時のみ意味あり: false = review-pending で disabled. true = 即時 enabled. */
14	  enabled: boolean;
15	}
16	
17	const EMPTY_FORM: RuleForm = {
18	  id: "",
19	  description: "",
20	  trigger_type: "tick",
21	  tick_sec: "300",
22	  event_kind: "",
23	  cooldown_sec: "300",
24	  instructions: "",
25	  enabled: false,
26	};
27	
28	interface Rule {
29	  id: string;
30	  description: string | null;
31	  trigger_type: "tick" | "event";
32	  tick_sec: number | null;
33	  event_kind: string | null;
34	  conditions: any;
35	  instructions: string;
36	  target: string | null;
37	  cooldown_sec: number;
38	  last_fired_at: number | null;
39	  enabled: boolean;
40	  added_at: number;
41	  added_by: string;
42	  removed_at: number | null;
43	  removed_by: string | null;
44	  removed_reason: string | null;
45	}
46	
47	interface RuleLog {
48	  id: number;
49	  ts: number;
50	  rule_id: string | null;
51	  action: string;
52	  detail: string | null;
53	  actor: string;
54	}
55	
56	type FormMode = { kind: "create" } | { kind: "edit"; ruleId: string };
57	
58	export function Rules() {
59	  const { data: rulesData, error, refetch } = useLiveQuery<{ rules: Rule[] }>(
60	    () => fetch("/v1/rules").then((r) => r.json()),
61	    ["rule.changed"],
62	  );
63	  const { data: logData } = useLiveQuery<{ logs: RuleLog[] }>(
64	    () => fetch("/v1/rules/log?limit=50").then((r) => r.json()),
65	    ["rule.changed"],
66	  );
67	  const [busy, setBusy] = useState<string | null>(null);
68	  const [mode, setMode] = useState<FormMode | null>(null);
69	  const [form, setForm] = useState<RuleForm>(EMPTY_FORM);
70	  const [formError, setFormError] = useState<string | null>(null);
71	  const [formSubmitting, setFormSubmitting] = useState(false);
72	  const [aiAssisting, setAiAssisting] = useState(false);
73	  const [eventKinds, setEventKinds] = useState<string[]>(["*"]);
74	
75	  // event_kind dropdown 用に backend から候補を取る
76	  useEffect(() => {
77	    fetch("/v1/rules/event-kinds")
78	      .then((r) => r.json())
79	      .then((j) => {
80	        if (Array.isArray(j.event_kinds)) setEventKinds(j.event_kinds);
81	      })
82	      .catch(() => {});
83	  }, []);
84	
85	  const startCreate = () => {
86	    setMode({ kind: "create" });
87	    setForm(EMPTY_FORM);
88	    setFormError(null);
89	  };
90	
91	  const startEdit = (r: Rule) => {
92	    setMode({ kind: "edit", ruleId: r.id });
93	    setForm({
94	      id: r.id,
95	      description: r.description ?? "",
96	      trigger_type: r.trigger_type,
97	      tick_sec: r.tick_sec != null ? String(r.tick_sec) : "300",
98	      event_kind: r.event_kind ?? "",
99	      cooldown_sec: String(r.cooldown_sec),
100	      instructions: r.instructions,
101	      enabled: r.enabled,
102	    });
103	    setFormError(null);
104	  };
105	
106	  const cancelForm = () => {
107	    setMode(null);
108	    setForm(EMPTY_FORM);
109	    setFormError(null);
110	  };
111	
112	  const toggle = async (id: string) => {
113	    setBusy(id);
114	    await fetch(`/v1/rules/${encodeURIComponent(id)}/toggle`, { method: "POST" });
115	    refetch();
116	    setBusy(null);
117	  };
118	
119	  const remove = async (id: string) => {
120	    if (!confirm(`rule "${id}" を削除しますか?`)) return;
121	    setBusy(id);
122	    const reason = prompt("削除理由 (任意):") ?? "";
123	    await fetch(`/v1/rules/${encodeURIComponent(id)}`, {
124	      method: "DELETE",
125	      headers: { "content-type": "application/json" },
126	      body: JSON.stringify({ reason }),
127	    });
128	    refetch();
129	    setBusy(null);
130	  };
131	
132	  const aiAssist = async () => {
133	    setAiAssisting(true);
134	    setFormError(null);
135	    try {
136	      const partial: any = {};
137	      if (form.id) partial.id = form.id;
138	      if (form.description) partial.description = form.description;
139	      partial.trigger_type = form.trigger_type;
140	      if (form.trigger_type === "tick" && form.tick_sec) partial.tick_sec = Number(form.tick_sec);
141	      if (form.trigger_type === "event" && form.event_kind) partial.event_kind = form.event_kind;
142	      if (form.cooldown_sec) partial.cooldown_sec = Number(form.cooldown_sec);
143	      if (form.instructions) partial.instructions = form.instructions;
144	
145	      const r = await fetch("/v1/rules/assist", {
146	        method: "POST",
147	        headers: { "content-type": "application/json" },
148	        body: JSON.stringify({ partial }),
149	      });
150	      if (!r.ok) {
151	        const j = await r.json().catch(() => ({}));
152	        setFormError(`AI 補完失敗: ${(j as any).error ?? r.status}`);
153	        return;
154	      }
155	      const j = await r.json();
156	      const rule = j.rule ?? {};
157	      // ユーザが既に埋めた値は上書きしない (空のスロットだけ AI 候補で埋める)
158	      setForm((prev) => ({
159	        id: prev.id || (rule.id ?? ""),
160	        description: prev.description || (rule.description ?? ""),
161	        trigger_type: prev.trigger_type, // ユーザ選択尊重
162	        tick_sec:
163	          prev.trigger_type === "tick"
164	            ? prev.tick_sec || (rule.tick_sec != null ? String(rule.tick_sec) : "300")
165	            : prev.tick_sec,
166	        event_kind:
167	          prev.trigger_type === "event"
168	            ? prev.event_kind || (rule.event_kind ?? "")
169	            : prev.event_kind,
170	        cooldown_sec: prev.cooldown_sec || (rule.cooldown_sec != null ? String(rule.cooldown_sec) : "300"),
171	        instructions: prev.instructions || (rule.instructions ?? ""),
172	        enabled: prev.enabled,
173	      }));
174	    } finally {
175	      setAiAssisting(false);
176	    }
177	  };
178	
179	  const submitForm = async () => {
180	    setFormError(null);
181	    if (!form.instructions) {
182	      setFormError("instructions は必須です");
183	      return;
184	    }
185	    if (mode?.kind === "create" && !form.id) {
186	      setFormError("id は必須です");
187	      return;
188	    }
189	    setFormSubmitting(true);
190	    try {
191	      const isEdit = mode?.kind === "edit";
192	      const body: any = {
193	        description: form.description || null,
194	        trigger_type: form.trigger_type,
195	        instructions: form.instructions,
196	        cooldown_sec: Number(form.cooldown_sec) || 60,
197	      };
198	      if (form.trigger_type === "tick") {
199	        body.tick_sec = Number(form.tick_sec) || 300;
200	        body.event_kind = null;
201	      } else {
202	        body.event_kind = form.event_kind || null;
203	        body.tick_sec = null;
204	      }
205	      let r: Response;
206	      if (isEdit) {
207	        r = await fetch(`/v1/rules/${encodeURIComponent((mode as any).ruleId)}`, {
208	          method: "PATCH",
209	          headers: { "content-type": "application/json" },
210	          body: JSON.stringify(body),
211	        });
212	      } else {
213	        body.id = form.id;
214	        body.conditions = [];
215	        body.enabled = form.enabled;
216	        r = await fetch("/v1/rules", {
217	          method: "PUT",
218	          headers: { "content-type": "application/json" },
219	          body: JSON.stringify(body),
220	        });
221	      }
222	      if (!r.ok) {
223	        const j = await r.json().catch(() => ({}));
224	        setFormError((j as any).error ?? `${r.status}`);
225	        return;
226	      }
227	      cancelForm();
228	      refetch();
229	    } finally {
230	      setFormSubmitting(false);
231	    }
232	  };
233	
234	  if (error) return <div className="text-danger">load error: {error.message}</div>;
235	  const rules = rulesData?.rules ?? [];
236	  const logs = logData?.logs ?? [];
237	
238	  return (
239	    <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
240	      <div className="lg:col-span-2 space-y-3">
241	        <header className="flex items-start gap-3">
242	          <div className="flex-1">
243	            <h1 className="font-semibold">Rules</h1>
244	            <p className="text-subtle text-sm mt-1">
245	              Concordia 内蔵 rule engine. tick または event で claude CLI を spawn し、
246	              chat 投稿 / rule の追加削除を判断する. 人間も rule を提案できる.
247	            </p>
248	          </div>
249	          {!mode && (
250	            <button
251	              onClick={startCreate}
252	              className="px-3 py-1 bg-accent/20 border border-accent text-accent rounded text-sm"
253	            >
254	              + propose rule
255	            </button>
256	          )}
257	        </header>
258	
259	        <div className="bg-surface border border-border rounded p-3 text-xs text-subtle">
260	          runtime kill switch (チャット mute / ルール有効化 / proposer 間隔 / Discord bot) と
261	          ワークスペース・リアクションWF・Lictor 設定は
262	          <a href="#/settings" className="text-accent"> 設定</a> ページに移動しました。
263	        </div>
264	
265	        {mode && (
266	          <RuleForm
267	            mode={mode}
268	            form={form}
269	            setForm={setForm}
270	            eventKinds={eventKinds}
271	            formError={formError}
272	            formSubmitting={formSubmitting}
273	            aiAssisting={aiAssisting}
274	            onAssist={() => void aiAssist()}
275	            onSubmit={() => void submitForm()}
276	            onCancel={cancelForm}
277	          />
278	        )}
279	
280	        {rules.length === 0 && (
281	          <div className="bg-surface border border-border rounded p-4 text-subtle text-sm">no rules</div>
282	        )}
283	
284	        {rules.map((r) => (
285	          <article key={r.id} className="bg-surface border border-border rounded p-3">
286	            <div className="flex items-center gap-2 text-xs">
287	              <span
288	                className={
289	                  "px-1.5 py-0.5 rounded " +
290	                  (r.enabled
291	                    ? "bg-ok/20 text-ok"
292	                    : !r.removed_at && r.added_by === "human"
293	                      ? "bg-warn/20 text-warn"
294	                      : "bg-subtle/20 text-subtle")
295	                }
296	              >
297	                {r.enabled
298	                  ? "enabled"
299	                  : !r.removed_at && r.added_by === "human"
300	                    ? "review待ち"
301	                    : "disabled"}
302	              </span>
303	              <span className="px-1.5 py-0.5 rounded bg-muted">{r.trigger_type}</span>
304	              {r.tick_sec && (
305	                <span className="text-subtle">every {r.tick_sec}s</span>
306	              )}
307	              {r.event_kind && (
308	                <span className="text-subtle">on {r.event_kind}</span>
309	              )}
310	              <span className="text-subtle">cooldown {r.cooldown_sec}s</span>
311	              <span className="ml-auto text-subtle">by {r.added_by}</span>
312	              <button
313	                onClick={() => startEdit(r)}
314	                disabled={busy === r.id}
315	                className="ml-2 text-subtle hover:text-accent"
316	              >
317	                edit
318	              </button>
319	              <button
320	                onClick={() => toggle(r.id)}
321	                disabled={busy === r.id}
322	                className="text-subtle hover:text-accent"
323	              >
324	                toggle
325	              </button>
326	              <button
327	                onClick={() => remove(r.id)}
328	                disabled={busy === r.id}
329	                className="text-subtle hover:text-danger"
330	              >
331	                remove
332	              </button>
333	            </div>
334	            <h2 className="mt-2 font-mono">{r.id}</h2>
335	            {r.description && <div className="text-subtle text-sm">{r.description}</div>}
336	            <details className="mt-2 text-xs">
337	              <summary className="cursor-pointer text-subtle">instructions</summary>
338	              <pre className="mt-1 bg-muted p-2 rounded whitespace-pre-wrap">{r.instructions}</pre>
339	            </details>
340	            <div className="mt-2 flex gap-3 text-[11px] text-subtle">
341	              {r.last_fired_at && <span>last fired: {fmtTs(r.last_fired_at)}</span>}
342	              {r.removed_at && (
343	                <span className="text-warn">
344	                  removed by {r.removed_by} @ {fmtTs(r.removed_at)} ({r.removed_reason ?? "?"})
345	                </span>
346	              )}
347	            </div>
348	          </article>
349	        ))}
350	      </div>
351	
352	      <aside className="space-y-2">
353	        <h2 className="font-semibold">最近のログ</h2>
354	        <ul className="space-y-1">
355	          {logs.map((l) => (
356	            <li
357	              key={l.id}
358	              className="bg-surface border border-border rounded px-2 py-1 text-[11px]"
359	            >
360	              <div className="flex items-center gap-2">
361	                <span className={actionColor(l.action)}>{l.action}</span>
362	                <span className="text-subtle font-mono">{l.rule_id ?? "-"}</span>
363	                <span className="text-subtle ml-auto">{fmtTs(l.ts)}</span>
364	              </div>
365	              {l.detail && (
366	                <div className="text-subtle mt-0.5 truncate">[{l.actor}] {l.detail}</div>
367	              )}
368	            </li>
369	          ))}
370	        </ul>
371	      </aside>
372	    </div>
373	  );
374	}
375	
376	function RuleForm({
377	  mode, form, setForm, eventKinds, formError, formSubmitting, aiAssisting,
378	  onAssist, onSubmit, onCancel,
379	}: {
380	  mode: FormMode;
381	  form: RuleForm;
382	  setForm: (f: RuleForm) => void;
383	  eventKinds: string[];
384	  formError: string | null;
385	  formSubmitting: boolean;
386	  aiAssisting: boolean;
387	  onAssist: () => void;
388	  onSubmit: () => void;
389	  onCancel: () => void;
390	}) {
391	  const isEdit = mode.kind === "edit";
392	  return (
393	    <form
394	      onSubmit={(e) => { e.preventDefault(); onSubmit(); }}
395	      className="bg-surface border border-border rounded p-3 space-y-2 text-sm"
396	    >
397	      <div className="flex items-center gap-2">
398	        <h2 className="font-semibold">
399	          {isEdit ? `rule "${(mode as any).ruleId}" を編集` : "新 rule 提案 (human)"}
400	        </h2>
401	        <button
402	          type="button"
403	          onClick={onAssist}
404	          disabled={aiAssisting}
405	          className="ml-auto px-2 py-1 bg-warn/20 border border-warn text-warn rounded text-xs disabled:opacity-50"
406	          title="未入力の項目を AI に補完してもらう (claude CLI 経由 / 既入力は尊重)"
407	        >
408	          {aiAssisting ? "AI 補完中…" : "✨ AI に補完してもらう"}
409	        </button>
410	      </div>
411	      <div className="grid grid-cols-2 gap-2">
412	        <Input
413	          label="id (unique)"
414	          value={form.id}
415	          onChange={(v) => setForm({ ...form, id: v })}
416	          placeholder="my-rule-id"
417	          required={!isEdit}
418	          disabled={isEdit}
419	        />
420	        <Input
421	          label="description"
422	          value={form.description}
423	          onChange={(v) => setForm({ ...form, description: v })}
424	          placeholder="どんな rule か (任意)"
425	        />
426	      </div>
427	      <div className="grid grid-cols-3 gap-2">
428	        <label className="flex flex-col">
429	          <span className="text-subtle text-xs">trigger</span>
430	          <select
431	            value={form.trigger_type}
432	            onChange={(e) => setForm({ ...form, trigger_type: e.target.value as "tick" | "event" })}
433	            className="bg-muted border border-border rounded px-2 py-1"
434	          >
435	            <option value="tick">tick (周期実行)</option>
436	            <option value="event">event (発生時)</option>
437	          </select>
438	        </label>
439	        {form.trigger_type === "tick" ? (
440	          <Input
441	            label="tick_sec (周期)"
442	            value={form.tick_sec}
443	            onChange={(v) => setForm({ ...form, tick_sec: v })}
444	            type="number"
445	          />
446	        ) : (
447	          <label className="flex flex-col">
448	            <span className="text-subtle text-xs">event_kind</span>
449	            <select
450	              value={form.event_kind}
451	              onChange={(e) => setForm({ ...form, event_kind: e.target.value })}
452	              className="bg-muted border border-border rounded px-2 py-1"
453	            >
454	              <option value="">(全 event / 任意)</option>
455	              {eventKinds.map((ek) => (
456	                <option key={ek} value={ek}>
457	                  {ek === "*" ? "* (全 event)" : ek}
458	                </option>
459	              ))}
460	            </select>
461	          </label>
462	        )}
463	        <Input
464	          label="cooldown_sec"
465	          value={form.cooldown_sec}
466	          onChange={(v) => setForm({ ...form, cooldown_sec: v })}
467	          type="number"
468	        />
469	      </div>
470	      <label className="flex flex-col">
471	        <span className="text-subtle text-xs">instructions (claude CLI に渡す指示)</span>
472	        <textarea
473	          value={form.instructions}
474	          onChange={(e) => setForm({ ...form, instructions: e.target.value })}
475	          className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono min-h-[100px]"
476	          placeholder="例: 「直近 30 分で edit が 0 件なら chitchat に『一服中?』 と投稿」"
477	          required
478	        />
479	      </label>
480	      {!isEdit && (
481	        <label className="flex items-center gap-2 text-xs text-subtle pt-1">
482	          <input
483	            type="checkbox"
484	            checked={form.enabled}
485	            onChange={(e) => setForm({ ...form, enabled: e.target.checked })}
486	          />
487	          <span>
488	            即時 enabled で投入する (off の場合は review 待ち disabled で保存され、 上の toggle で有効化)
489	          </span>
490	        </label>
491	      )}
492	      {formError && <div className="text-danger text-xs">{formError}</div>}
493	      <div className="flex gap-2 justify-end">
494	        <button type="button" onClick={onCancel} className="text-subtle text-sm">cancel</button>
495	        <button
496	          type="submit"
497	          disabled={formSubmitting}
498	          className="px-3 py-1 bg-accent/30 border border-accent text-text rounded text-sm disabled:opacity-50"
499	        >
500	          {formSubmitting
501	            ? "..."
502	            : isEdit
503	              ? "save"
504	              : form.enabled
505	                ? "propose & enable"
506	                : "propose (review)"}
507	        </button>
508	      </div>
509	      {!isEdit && (
510	        <p className="text-subtle text-[11px]">
511	          既定は <strong>review 待ち</strong> (disabled で保存). 中身を確認してから toggle で有効化.
512	          チェックを入れた場合は即時 enabled になり、 AI が「不要」と判断すれば後から削除される可能性あり (log に残る).
513	        </p>
514	      )}
515	    </form>
516	  );
517	}
518	
519	function Input({
520	  label, value, onChange, placeholder, type = "text", required, disabled,
521	}: {
522	  label: string;
523	  value: string;
524	  onChange: (v: string) => void;
525	  placeholder?: string;
526	  type?: string;
527	  required?: boolean;
528	  disabled?: boolean;
529	}) {
530	  return (
531	    <label className="flex flex-col">
532	      <span className="text-subtle text-xs">{label}{required && <span className="text-danger ml-1">*</span>}</span>
533	      <input
534	        type={type}
535	        value={value}
536	        onChange={(e) => onChange(e.target.value)}
537	        placeholder={placeholder}
538	        className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono disabled:opacity-50"
539	        required={required}
540	        disabled={disabled}
541	      />
542	    </label>
543	  );
544	}
545	
546	function actionColor(action: string): string {
547	  switch (action) {
548	    case "fire":   return "px-1 rounded bg-accent/20 text-accent";
549	    case "add":    return "px-1 rounded bg-ok/20 text-ok";
550	    case "remove": return "px-1 rounded bg-warn/20 text-warn";
551	    case "skip":   return "px-1 rounded bg-subtle/20 text-subtle";
552	    case "error":  return "px-1 rounded bg-danger/20 text-danger";
553	    default:       return "px-1 rounded bg-muted text-subtle";
554	  }
