1	/**
2	 * buildApp ベースの API テスト用ファクトリ.
3	 *
4	 * これまで各 API テストが ~30 行の repos + buildApp セットアップを逐語コピーし、
5	 * しかも AppDeps の必須 dep (participants / prs / delegation / modelCatalog 等) を
6	 * 渡し漏れていた。本 helper は AppDeps を完全に満たした app を 1 行で組み、
7	 * 副作用 (spawn token / delegation prompt のリポ直下書き込み) を tmpdir に隔離し、
8	 * 生成リソースを cleanup レジストリ経由で必ず解放する。
9	 */
10	
11	import type Database from "better-sqlite3";
12	import { join } from "node:path";
13	import { buildApp, type AppDeps } from "../../src/app.js";
14	import { AdminState } from "../../src/admin/state.js";
15	import { ChatRepo } from "../../src/db/chat-repo.js";
16	import { DayReportsRepo } from "../../src/db/day-reports-repo.js";
17	import { DelegationRepo } from "../../src/db/delegation-repo.js";
18	import {
19	  makeDiscordConfigRepo,
20	  makeDiscordPendingQuestionsRepo,
21	  makeDiscordSessionChannelsRepo,
22	} from "../../src/db/discord-repo.js";
23	import { ModelCatalogRepo } from "../../src/db/model-catalog-repo.js";
24	import { makeParticipantsRepo } from "../../src/db/participants-repo.js";
25	import { PersonasRepo } from "../../src/db/personas-repo.js";
26	import { PrRecordsRepo } from "../../src/db/pr-records-repo.js";
27	import { ProcessesRepo } from "../../src/db/processes-repo.js";
28	import { RulesRepo } from "../../src/db/rules-repo.js";
29	import { SessionTaskRecordsRepo } from "../../src/db/session-task-records-repo.js";
30	import { SessionsRepo } from "../../src/db/sessions-repo.js";
31	import { SkillsRepo } from "../../src/db/skills-repo.js";
32	import { StatsRepo } from "../../src/db/stats-repo.js";
33	import { TasksRepo } from "../../src/db/tasks-repo.js";
34	import { TranscriptLogsRepo } from "../../src/db/transcript-logs-repo.js";
35	import { DelegationService } from "../../src/delegation/service.js";
36	import { seedDelegationTemplates } from "../../src/delegation/seed.js";
37	import { Dispatcher } from "../../src/dispatcher.js";
38	import { seedPersonas } from "../../src/personas/seeds.js";
39	import { ProcessManager } from "../../src/processes/manager.js";
40	import { loadConfig, type ConcordiaConfig } from "../../src/shared/config.js";
41	import { registerCleanup } from "./cleanup.js";
42	import { makeTestDb, makeTestDir } from "./db.js";
43	
44	export interface TestAppOptions {
45	  /** 事前に seed 済みの DB を共有する場合に指定 (省略時は makeTestDb)。 */
46	  db?: Database.Database;
47	  /** loadConfig({}) ベースの config への上書き (adminToken 等)。 */
48	  config?: Partial<ConcordiaConfig>;
49	  /** Dispatcher の rng (default: () => 1)。 */
50	  rng?: () => number;
51	}
52	
53	export interface TestAppEnv {
54	  app: ReturnType<typeof buildApp>;
55	  db: Database.Database;
56	  repo: SessionsRepo;
57	  tasks: TasksRepo;
58	  chat: ChatRepo;
59	  skills: SkillsRepo;
60	  rules: RulesRepo;
61	  dayReports: DayReportsRepo;
62	  personas: PersonasRepo;
63	  processes: ProcessesRepo;
64	  stats: StatsRepo;
65	  prs: PrRecordsRepo;
66	  sessionTaskRecords: SessionTaskRecordsRepo;
67	  transcriptLogs: TranscriptLogsRepo;
68	  pendingQuestions: ReturnType<typeof makeDiscordPendingQuestionsRepo>;
69	  discordChannels: ReturnType<typeof makeDiscordSessionChannelsRepo>;
70	  discordConfig: ReturnType<typeof makeDiscordConfigRepo>;
71	  participants: ReturnType<typeof makeParticipantsRepo>;
72	  delegation: DelegationRepo;
73	  delegationService: DelegationService;
74	  modelCatalog: ModelCatalogRepo;
75	  adminState: AdminState;
76	  processManager: ProcessManager;
77	  dispatcher: Dispatcher;
78	  config: ConcordiaConfig;
79	  logsDir: string;
80	}
81	
82	export function makeTestApp(opts: TestAppOptions = {}): TestAppEnv {
83	  const db = opts.db ?? makeTestDb();
84	  const repo = new SessionsRepo(db);
85	  const tasks = new TasksRepo(db);
86	  const chat = new ChatRepo(db);
87	  const skills = new SkillsRepo(db);
88	  const rules = new RulesRepo(db);
89	  const dayReports = new DayReportsRepo(db);
90	  const personas = new PersonasRepo(db);
91	  seedPersonas(personas);
92	  const processes = new ProcessesRepo(db);
93	  const stats = new StatsRepo(db);
94	  const prs = new PrRecordsRepo(db);
95	  const sessionTaskRecords = new SessionTaskRecordsRepo(db);
96	  const transcriptLogs = new TranscriptLogsRepo(db);
97	  const pendingQuestions = makeDiscordPendingQuestionsRepo(db);
98	  const discordChannels = makeDiscordSessionChannelsRepo(db);
99	  const discordConfig = makeDiscordConfigRepo(db);
100	  const participants = makeParticipantsRepo(db);
101	  const delegation = new DelegationRepo(db);
102	  seedDelegationTemplates(delegation);
103	  const modelCatalog = new ModelCatalogRepo(db);
104	  const adminState = new AdminState(db);
105	
106	  // 副作用の隔離: logsDir / spawn token / delegation prompt を全て tmpdir に向ける。
107	  // CONCORDIA_SPAWN_TOKEN_PATH を設定しないと buildApp (spawnRouter) が
108	  // process.cwd() = リポ直下に .spawn.token を書いてしまう。
109	  const logsDir = makeTestDir("concordia-test-logs-");
110	  const prevTokenPath = process.env.CONCORDIA_SPAWN_TOKEN_PATH;
111	  process.env.CONCORDIA_SPAWN_TOKEN_PATH = join(logsDir, ".spawn.token");
112	  registerCleanup(() => {
113	    if (prevTokenPath === undefined) delete process.env.CONCORDIA_SPAWN_TOKEN_PATH;
114	    else process.env.CONCORDIA_SPAWN_TOKEN_PATH = prevTokenPath;
115	  });
116	
117	  const delegationService = new DelegationService({
118	    repo: delegation,
119	    personas,
120	    promptsDir: join(logsDir, "delegation-prompts"),
121	    spawn: () => ({ ok: true, pid: null, command: [] }),
122	  });
123	
124	  const processManager = new ProcessManager({ repo: processes, logsDir });
125	  const dispatcher = new Dispatcher({ sessions: repo, tasks, chat, rng: opts.rng ?? (() => 1) });
126	  const config: ConcordiaConfig = {
127	    ...loadConfig({}),
128	    anthropicApiKey: "",
129	    ...opts.config,
130	  };
131	
132	  const deps: AppDeps = {
133	    repo, tasks, chat, skills, rules, dayReports, personas, processes, stats, prs,
134	    sessionTaskRecords, transcriptLogs, pendingQuestions, discordChannels, discordConfig,
135	    participants, delegation, delegationService, modelCatalog, adminState,
136	    processManager, dispatcher,
137	    dailyScheduler: { stop: () => {}, runOnce: async () => {} },
138	    config,
139	    startedAt: new Date().toISOString(),
140	    sweeperRunOnce: () => {},
141	    toolPath: "/abs/tools/concordia-hook.mjs",
142	    publicUrl: "http://127.0.0.1:17330",
143	  };
144	
145	  return {
146	    app: buildApp(deps),
147	    db, repo, tasks, chat, skills, rules, dayReports, personas, processes, stats, prs,
148	    sessionTaskRecords, transcriptLogs, pendingQuestions, discordChannels, discordConfig,
149	    participants, delegation, delegationService, modelCatalog, adminState,
150	    processManager, dispatcher, config, logsDir,
151	  };
152	}
153

