/**
 * セッション別 提案レートリミット — dispatcher が 1 session へ出す提案 (proposal)
 * の発火数を「窓 (秒) と上限回数」で絞る安全弁。
 *
 * 既存の runtime kill-switch (chat-mute / cost-budget) と同じく、 設定値も
 * カウンタ状態も `schema_meta` に永続化する (AdminState が所有)。 ここは
 *
 *   1. レート判定そのものを pure 関数 `evaluateProposalRate` に隔離し
 *   2. AdminState から config / counter state を read-modify-write する薄い
 *      `ProposalRateLimiter` で dispatcher に注入する verdict を作る
 *
 * という 2 層構成。 dispatcher は `proposalGate(session_id)` で verdict を受け、
 * allowed=false のときは今回の提案を enqueue せず理由をログする (窓が明けたら
 * カウンタがリセットされ再開する)。
 *
 * 無効化: max_count <= 0 は「上限なし (= 制限しない)」として常に allow する。
 */

import type { AdminState } from "./state.js";

export interface ProposalRateConfig {
  /** 窓の長さ (秒)。 この窓内で max_count を超えた提案を skip する。 */
  window_sec: number;
  /** 窓内に許す提案数の上限。 0 以下 = 無制限 (制限しない)。 */
  max_count: number;
}

export interface ProposalRateState {
  /** 現在の窓の開始時刻 (epoch 秒)。 */
  window_start_sec: number;
  /** 現在の窓で既に許可した提案数。 */
  count: number;
}

export interface ProposalRateVerdict {
  allowed: boolean;
  /** allowed=false のときの skip 理由 (ログ用)。 */
  reason?: string;
}

/**
 * レート判定 (pure)。 prev (前回のカウンタ状態) と config・現在時刻から、
 * 今回の提案を許可するか + 次に永続化すべき state を返す。
 *
 * - max_count <= 0: 無制限。 常に allow (state はそのまま据え置き)。
 * - 窓を跨いだ (now - window_start >= window): 窓をリセットして count=0 から。
 * - 窓内で count >= max_count: skip (count は増やさない)。
 * - それ以外: allow して count を 1 増やす。
 */
export function evaluateProposalRate(
  config: ProposalRateConfig,
  prev: ProposalRateState | undefined,
  nowSec: number,
): { allowed: boolean; reason?: string; state: ProposalRateState } {
  const base: ProposalRateState = prev ?? { window_start_sec: nowSec, count: 0 };

  // 無制限 (制限 OFF)。 state は触らない。
  if (!Number.isFinite(config.max_count) || config.max_count <= 0) {
    return { allowed: true, state: base };
  }

  const window = Number.isFinite(config.window_sec) && config.window_sec > 0 ? config.window_sec : 60;
  let { window_start_sec, count } = base;

  // 窓が明けていればリセットして再開。
  if (nowSec - window_start_sec >= window) {
    window_start_sec = nowSec;
    count = 0;
  }

  if (count >= config.max_count) {
    return {
      allowed: false,
      reason: `proposal rate limit reached: ${count}/${config.max_count} within ${window}s window`,
      state: { window_start_sec, count },
    };
  }

  return { allowed: true, state: { window_start_sec, count: count + 1 } };
}

/**
 * AdminState (schema_meta 永続化) を back end にした session 別レートリミッタ。
 * dispatcher の `proposalGate` に `check` を配線する。
 */
export class ProposalRateLimiter {
  constructor(
    private readonly admin: AdminState,
    /** 現在時刻プロバイダ (epoch 秒)。 テスト用に注入可。 */
    private readonly now: () => number = () => Math.floor(Date.now() / 1000),
  ) {}

  /** 1 提案ぶんのレートを確認し、 カウンタ状態を永続化して verdict を返す。 */
  check(sessionId: string): ProposalRateVerdict {
    const config = this.admin.getEffectiveProposalRate(sessionId);
    const prev = this.admin.getProposalRateStateFor(sessionId);
    const res = evaluateProposalRate(config, prev, this.now());
    // 窓リセットや count 増加を取りこぼさないよう、 allow/skip いずれでも永続化する。
    this.admin.setProposalRateStateFor(sessionId, res.state);
    return { allowed: res.allowed, reason: res.reason };
  }
}

