  };
}

/** グローバル既定を設定 (window / max_count を許容範囲に clamp)。 */
setProposalRateDefault(windowSec: number, maxCount: number): void {
  this.setRaw(KEY_PROPOSAL_RATE_DEFAULT, JSON.stringify(normalizeRateConfig(windowSec, maxCount)));
}

/** session 別の上書き辞書 (空なら {})。 */
getProposalRateOverrides(): Record<string, ProposalRateConfig> {
  const raw = this.getRaw(KEY_PROPOSAL_RATE_OVERRIDES);
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      const out: Record<string, ProposalRateConfig> = {};
      for (const [sid, v] of Object.entries(parsed as Record<string, unknown>)) {
        const cfg = parseRateConfig(typeof v === "string" ? v : JSON.stringify(v));
        if (cfg) out[sid] = cfg;
      }
      return out;
    }
  } catch {
    // 壊れた値は無視 (空辞書扱い)。
  }
  return {};
}

/** session 別の上書きを 1 件 upsert。 */
setProposalRateOverride(sessionId: string, windowSec: number, maxCount: number): void {
  const sid = sessionId.trim();
  if (!sid) return;
  const cur = this.getProposalRateOverrides();
  cur[sid] = normalizeRateConfig(windowSec, maxCount);
  this.setRaw(KEY_PROPOSAL_RATE_OVERRIDES, JSON.stringify(cur));
}

/** session 別の上書きを 1 件削除 (既定に戻す)。 */
deleteProposalRateOverride(sessionId: string): void {
  const cur = this.getProposalRateOverrides();
  if (!Object.prototype.hasOwnProperty.call(cur, sessionId.trim())) return;
  delete cur[sessionId.trim()];
  this.setRaw(KEY_PROPOSAL_RATE_OVERRIDES, JSON.stringify(cur));
}

/** 指定 session の実効レート設定 (override ?? default)。 */
getEffectiveProposalRate(sessionId: string): ProposalRateConfig {
  return this.getProposalRateOverrides()[sessionId] ?? this.getProposalRateDefault();
}

/** カウンタ状態の全辞書 (空なら {})。 */
getProposalRateState(): Record<string, ProposalRateState> {
  const raw = this.getRaw(KEY_PROPOSAL_RATE_STATE);
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
      return parsed as Record<string, ProposalRateState>;
    }
  } catch {
    // 壊れた値は無視。
  }
  return {};
}

/** 指定 session のカウンタ状態 (未記録なら undefined)。 */
getProposalRateStateFor(sessionId: string): ProposalRateState | undefined {
  return this.getProposalRateState()[sessionId];
}

/** 指定 session のカウンタ状態を upsert (window リセット / count 増加を永続化)。 */
setProposalRateStateFor(sessionId: string, state: ProposalRateState): void {
  const cur = this.getProposalRateState();
  cur[sessionId] = state;
  this.setRaw(KEY_PROPOSAL_RATE_STATE, JSON.stringify(cur));
}

snapshot(): {
  chat_muted: boolean;
  rules_enabled: boolean;
  rule_proposer_interval_sec: number;
  workspace_root: string;
  workspace_roots: string[];
  github_org: string;
  reaction_workflow_enabled: boolean;
  lictor_mode: LictorMode;
  lictor_dev_path: string;
  lictor_prod_exe: string;
