constructor(private readonly deps: DispatcherDeps) {
  this.rng = deps.rng ?? Math.random;
  this.now = deps.now ?? (() => new Date());
  this.isChatMuted = deps.isChatMuted ?? (() => false);
  this.isCostBlocked = deps.isCostBlocked ?? (() => false);
  this.proposalGate = deps.proposalGate ?? (() => ({ allowed: true }));
}

/**
 * 1 session への提案 (task) を enqueue する単一ゲート。 セッション別レート
 * リミットを確認し、 窓内で上限に達していれば enqueue せず理由をログする。
 * 既存の全 enqueue 経路をここに通すことで、 提案発火点に 1 箇所だけゲートを差す。
 */
private propose(input: Parameters<TasksRepo["enqueue"]>[0]): boolean {
  const verdict = this.proposalGate(input.session_id);
  if (!verdict.allowed) {
    dispatcherLog.info(
      { session_id: input.session_id, kind: input.kind, reason: verdict.reason },
      "proposal skipped (per-session rate limit)",
    );
    return false;
  }
  this.deps.tasks.enqueue(input);
  return true;
}

