   * 既存の全 enqueue 経路をここに通すことで、 提案発火点に 1 箇所だけゲートを差す。
   */
  private propose(input: Parameters<TasksRepo["enqueue"]>[0]): boolean {
    const verdict = this.proposalGate(input.session_id);
    if (!verdict.allowed) {
      dispatcherLog.info(
        { session_id: input.session_id, kind: input.kind, reason: verdict.reason },
