export interface DispatcherDeps {
  sessions: SessionsRepo;
  tasks: TasksRepo;
  chat: ChatRepo;
  rng?: () => number;
  /** 深夜帯判定に使う現在時刻プロバイダ. 既定はシステム時計 (テスト用に注入可). */
