// ─── セッション別 提案レートリミット (窓 + 上限回数) ─────────────────────

interface RateConfig { window_sec: number; max_count: number }
interface ProposalRate {
  default: RateConfig;
  overrides: Record<string, RateConfig>;
  window_min_sec: number;
  window_max_sec: number;
  max_count_min: number;
  max_count_max: number;
}

export function ProposalRateSection() {
  const [data, setData] = useState<ProposalRate | null>(null);
  const [busy, setBusy] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [winDraft, setWinDraft] = useState("");
  const [maxDraft, setMaxDraft] = useState("");
  // 個別上書き追加フォーム。
  const [ovSession, setOvSession] = useState("");
  const [ovWin, setOvWin] = useState("");
  const [ovMax, setOvMax] = useState("");

  useEffect(() => { void refresh(); }, []);

  async function refresh() {
    try {
      const s = (await fetch("/v1/admin/proposal-rate").then((r) => r.json())) as ProposalRate;
      setData(s);
      setWinDraft(String(s.default.window_sec));
      setMaxDraft(String(s.default.max_count));
      setError(null);
    } catch (err) { setError((err as Error).message); }
  }

  async function applyDefault() {
    const w = Number(winDraft), m = Number(maxDraft);
    if (!Number.isFinite(w) || !Number.isFinite(m)) { setError("数値を入力"); return; }
    setBusy("default"); setError(null);
    try { await putJson("/v1/admin/proposal-rate", { window_sec: w, max_count: m }); await refresh(); }
    catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function addOverride() {
    const sid = ovSession.trim();
    const w = Number(ovWin), m = Number(ovMax);
    if (!sid || !Number.isFinite(w) || !Number.isFinite(m)) { setError("session_id と数値を入力"); return; }
    setBusy("add-ov"); setError(null);
    try {
      await putJson("/v1/admin/proposal-rate/override", { session_id: sid, window_sec: w, max_count: m });
      setOvSession(""); setOvWin(""); setOvMax("");
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  async function removeOverride(sid: string) {
    setBusy(`rm:${sid}`); setError(null);
    try {
      const r = await fetch(`/v1/admin/proposal-rate/override/${encodeURIComponent(sid)}`, { method: "DELETE" });
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      await refresh();
    } catch (err) { setError((err as Error).message); } finally { setBusy(null); }
  }

  const fmtRate = (c: RateConfig) =>
    c.max_count <= 0 ? "無制限 (制限 OFF)" : `${c.window_sec}秒 / ${c.max_count}回`;
  const overrides = data ? Object.entries(data.overrides) : [];

  return (
    <section className="space-y-3">
      <div>
        <h2 className="font-semibold text-sm">提案レートリミット (session 別)</h2>
        <p className="text-subtle text-xs mt-0.5">
          dispatcher が 1 session へ出す提案 (chitchat / chat-reply / review 等) を「窓 (秒) 内の
          上限回数」で絞る。 窓内で上限に達すると今回の提案を skip し、 窓が明けたら再開する。
          上限回数 0 = 無制限 (制限 OFF)。 設定 / カウンタ状態は schema_meta 永続化で即時反映。
        </p>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-2">
        <div className="text-sm font-medium">グローバル既定</div>
        <div className="flex items-center gap-2 flex-wrap">
          <span className="text-xs text-subtle shrink-0">現在:</span>
          <span className="shrink-0 px-2 py-0.5 rounded text-xs border bg-ok/20 border-ok text-ok font-mono">
            {data ? fmtRate(data.default) : "..."}
          </span>
          <label className="text-xs text-subtle ml-auto">窓(秒)
            <input
              type="number" min={data?.window_min_sec ?? 1} max={data?.window_max_sec ?? 86400}
              value={winDraft} onChange={(e) => setWinDraft(e.target.value)} disabled={busy === "default"}
              className="ml-1 bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
            />
          </label>
          <label className="text-xs text-subtle">上限(回)
            <input
              type="number" min={data?.max_count_min ?? 0} max={data?.max_count_max ?? 100000}
              value={maxDraft} onChange={(e) => setMaxDraft(e.target.value)} disabled={busy === "default"}
              className="ml-1 bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-20"
            />
          </label>
          <button
            disabled={busy === "default" || (winDraft === String(data?.default.window_sec ?? "") && maxDraft === String(data?.default.max_count ?? ""))}
            onClick={() => void applyDefault()}
            className="shrink-0 px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >apply</button>
        </div>
      </div>

      <div className="bg-muted/40 border border-border rounded p-3 space-y-3">
        <div>
          <div className="text-sm font-medium">session 個別の上書き</div>
          <div className="text-xs text-subtle mt-0.5">
            特定 session だけ既定と違うレートにする。 上限 0 でその session を制限対象外にできる。
          </div>
        </div>

        <div className="flex items-center gap-2 flex-wrap">
          <input
            type="text" value={ovSession} onChange={(e) => setOvSession(e.target.value)}
            placeholder="session_id" disabled={busy === "add-ov"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono flex-1 min-w-[160px]"
          />
          <input
            type="number" value={ovWin} onChange={(e) => setOvWin(e.target.value)}
            placeholder="窓(秒)" disabled={busy === "add-ov"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-24"
          />
          <input
            type="number" value={ovMax} onChange={(e) => setOvMax(e.target.value)}
            placeholder="上限(回)" disabled={busy === "add-ov"}
            className="bg-muted border border-border rounded px-2 py-1 text-sm font-mono w-20"
          />
          <button
            disabled={busy === "add-ov" || !ovSession.trim() || ovWin === "" || ovMax === ""}
            onClick={() => void addOverride()}
            className="px-3 py-1 bg-accent/15 border border-accent text-accent rounded text-xs disabled:opacity-40"
          >追加 / 上書き</button>
        </div>

        {overrides.length === 0 ? (
          <div className="text-xs text-subtle">(上書きなし — 全 session が既定を使用)</div>
        ) : (
          <ul className="space-y-1">
            {overrides.map(([sid, cfg]) => (
              <li key={sid} className="flex items-center gap-2 text-sm bg-surface border border-border rounded px-2 py-1">
                <span className="font-mono text-xs truncate flex-1" title={sid}>{sid}</span>
                <span className="text-subtle">→</span>
                <span className="font-mono text-xs">{fmtRate(cfg)}</span>
                <button
                  disabled={busy === `rm:${sid}`}
                  onClick={() => void removeOverride(sid)}
                  className="ml-2 text-subtle hover:text-danger text-xs"
                >削除</button>
              </li>
            ))}
          </ul>
        )}
      </div>

      {error && <div className="text-danger text-xs">{error}</div>}
    </section>
  );
}

