import { describe, it, expect, beforeEach } from "vitest";
import { makeTestDb } from "./helpers/db.js";
import { AdminState } from "../src/admin/state.js";
import {
  evaluateProposalRate,
  ProposalRateLimiter,
} from "../src/admin/proposal-rate-limit.js";

describe("evaluateProposalRate (pure)", () => {
  it("窓内で上限に達したら skip、 窓が明けたら count リセットで再開", () => {
    const cfg = { window_sec: 60, max_count: 2 };
    // 窓開始 t=1000。 1 回目 / 2 回目は allow、 count が積み上がる。
    let r = evaluateProposalRate(cfg, undefined, 1000);
    expect(r.allowed).toBe(true);
    expect(r.state).toEqual({ window_start_sec: 1000, count: 1 });

    r = evaluateProposalRate(cfg, r.state, 1010);
    expect(r.allowed).toBe(true);
    expect(r.state).toEqual({ window_start_sec: 1000, count: 2 });

