    expect(r.state).toEqual({ window_start_sec: 1000, count: 2 });

    // 窓が明ける (1000 + 60 = 1060 以降) → リセットして再開。
    r = evaluateProposalRate(cfg, r.state, 1061);
    expect(r.allowed).toBe(true);
    expect(r.state).toEqual({ window_start_sec: 1061, count: 1 });
  });

  it("max_count <= 0 は無制限 (常に allow、 state 据え置き)", () => {
