describe("Dispatcher proposalGate — セッション別 提案レートリミット", () => {
  let env: ReturnType<typeof fresh>;
  beforeEach(() => { env = fresh(); });

  it("proposalGate が allowed=false を返すと提案を enqueue しない (skip)", () => {
    startSession(env.sessions, "a");
    const d = new Dispatcher({
      ...env, rng: () => 0.99, now: DAYTIME,
      proposalGate: () => ({ allowed: false, reason: "rate limit" }),
    });
    for (let i = 0; i < 5; i++) {
      env.sessions.appendEvent({ session_id: "a", ts: i, kind: "edit", payload: { file: "src/foo.ts" } });
    }
    d.onEventAppended(env.sessions.findSession("a")!, 5);
    // review-summary が出るはずの条件だが gate で skip される。
    expect(env.tasks.pull("a").length).toBe(0);
  });

  it("上限到達でスキップ → 窓明けで再開 (gate を通った提案だけ enqueue)", () => {
    startSession(env.sessions, "a");
    startSession(env.sessions, "b");
    // b への chat-reply を 2 回まで許可するゲートをクロージャで作る。
    let allowed = 2;
    let reopened = false;
    const d = new Dispatcher({
      ...env, rng: () => 0.0, now: DAYTIME, // 確率 0 で必ず reply 候補に乗せる
      proposalGate: (sid) => {
        if (sid !== "b") return { allowed: true };
        if (allowed > 0) { allowed--; return { allowed: true }; }
        if (reopened) return { allowed: true };
        return { allowed: false, reason: "window full" };
      },
    });

    // 報告 channel (reply 確率 0.8) に 3 回投稿 → b へ 3 回 chat-reply 候補。
    for (let i = 0; i < 3; i++) {
      d.onChatPosted({ id: i + 1, channel: "報告", session_id: "a", text: "x", author_label: "t", is_actionable: false });
    }
    // 最初の 2 回だけ通って 3 回目は skip。
    expect(env.tasks.pull("b").filter((t) => t.kind === "chat-reply").length).toBe(2);

    // 窓明けを模擬して再開。
    reopened = true;
    d.onChatPosted({ id: 99, channel: "報告", session_id: "a", text: "y", author_label: "t", is_actionable: false });
    expect(env.tasks.pull("b").filter((t) => t.kind === "chat-reply").length).toBe(1);
  });
});

